// FIX L6: Normalizar el campo 'pillar' que puede llegar como boolean true o string 'true'.
// Tambien normalizar duration_sec a numero.
const d = $input.first().json;

if (!d.content_id) throw new Error('Missing content_id in payload');
if (!d.client_id) throw new Error('Missing client_id in payload');

// Normalizar pillar: acepta boolean true O string 'true'
const pillar = d.pillar === true || d.pillar === 'true' || d.pillar === 1 || d.pillar === '1';

// Normalizar duration_sec a numero
const duration_sec = parseInt(d.duration_sec) || 0;

console.log(`[content-repurposing] content_id=${d.content_id}, pillar=${pillar}, duration_sec=${duration_sec}`);

return [{ json: {
  ...d,
  pillar: pillar,
  duration_sec: duration_sec
} }];

const piece = $input.first().json;
const derivatives = [
  { type: 'reel_30s', platform: 'instagram', priority: 1 },
  { type: 'short_60s', platform: 'youtube', priority: 1 },
  { type: 'tiktok_15s', platform: 'tiktok', priority: 2 },
  { type: 'carousel_5slides', platform: 'instagram', priority: 2 },
  { type: 'tweet_thread', platform: 'twitter', priority: 3 },
  { type: 'linkedin_post', platform: 'linkedin', priority: 3 },
  { type: 'newsletter_section', platform: 'beehiiv', priority: 2 },
  { type: 'blog_post_1500w', platform: 'web', priority: 3 }
];

console.log(`[content-repurposing] Generando ${derivatives.length} derivadas para content_id=${piece.content_id}`);

return derivatives.map(d => ({
  json: {
    ...d,
    parent_id: piece.content_id,
    client_id: piece.client_id,
    status: 'pending_derivative',
    created_at: new Date().toISOString()
  }
}));

// Agrupar todas las derivadas insertadas y formatear mensaje para el equipo
const items = $input.all().map(i => i.json);

const p1 = items.filter(d => d.priority === 1);
const p2 = items.filter(d => d.priority === 2);
const p3 = items.filter(d => d.priority === 3);

const formatList = arr => arr.map(d => `• ${d.type} (${d.platform})`).join('\n');

const parentId = $('Code - Normalize Payload').item.json.content_id;
const clientId = $('Code - Normalize Payload').item.json.client_id;
const url = $('Code - Normalize Payload').item.json.url;

const msg = `Nuevo pilar subido! Checklist de derivadas a generar:\n\nP1 - Urgente:\n${formatList(p1)}\n\nP2 - Esta semana:\n${formatList(p2)}\n\nP3 - Cuando haya tiempo:\n${formatList(p3)}\n\nCliente: ${clientId}\nURL: ${url || 'sin url'}\nTotal: ${items.length} piezas`;

return [{ json: { message: msg, total: items.length, client_id: clientId, parent_id: parentId } }];
